  const value = useMemo<SettingsContextValue>(
    () => ({
      ...settings,
      isLoading,
      refreshSettings: fetchSettings,
    }),
    [settings, isLoading, fetchSettings],
  );

  return <SettingsContext.Provider value={value}>{children}</SettingsContext.Provider>;
};

