  const normalizedStatus: UploadProgressState['status'] =
    progress.status === 'pending' ||
    progress.status === 'uploading' ||
    progress.status === 'completed' ||
    progress.status === 'failed'
      ? progress.status
      : 'failed';

  return {
    status: normalizedStatus,
    message: progress.message || '',
