          setLoading(false);
        });

        eventSource.addEventListener('error', (errorEvent: MessageEvent<string>) => {
          let errorMsg = 'An unknown error occurred during processing.';
          if (errorEvent.data) {
            try {
              const data = JSON.parse(errorEvent.data) as { message?: string };
              errorMsg = data.message || errorMsg;
            } catch {
              errorMsg = errorEvent.data;
            }
          }

          setBatchUploadProgress({
            ...EMPTY_BATCH_PROGRESS,
            visible: false,
            message: errorMsg,
            status: 'error',
          });
          setBatchUploadFeedback({ visible: true, message: errorMsg, type: 'error' });
          eventSource.close();
          setLoading(false);
        });
      } else {
        const { added = [], skipped = [], errors = [] } = response;
        let feedbackMessage = `Batch upload complete. Added: ${added.length}. Skipped: ${skipped.length}.`;

        if (errors.length > 0) {
          const errorDetails = errors.map((item) => `${item.directory}: ${item.message}`).join('; ');
          feedbackMessage += ` Errors: ${errors.length} (${errorDetails})`;
          setBatchUploadFeedback({ visible: true, message: feedbackMessage, type: 'error' });
        } else {
          setBatchUploadFeedback({ visible: true, message: feedbackMessage, type: 'success' });
        }

        await fetchProblems();
        setLoading(false);
      }
    } catch (errorValue) {
      const errorMsg = getErrorMessage(errorValue, 'Failed to batch upload problems.');
      setBatchUploadFeedback({ visible: true, message: errorMsg, type: 'error' });
      setBatchUploadProgress({
        ...EMPTY_BATCH_PROGRESS,
        visible: false,
        message: errorMsg,
        status: 'error',
      });
      setLoading(false);
    } finally {
      if (batchUploadInputRef.current) {
        batchUploadInputRef.current.value = '';
      }
    }
  }

handleSave = async ({ problemData, pdfFile, zipFile }: ProblemSavePayload) => {
    const isEditing = Boolean(editingProblem);
    setUploadProgress({ status: 'pending', message: 'Initiating save...' });

    try {
      let problemIdForUpload = problemData.id;

      if (isEditing && editingProblem) {
        await adminService.updateProblem(editingProblem.id, problemData);
      } else {
        const data = await adminService.createProblem(problemData);
        problemIdForUpload = data.id || problemData.id;
      }

      if (pdfFile || zipFile) {
        const fileData = new FormData();
        if (pdfFile) {
          fileData.append('problemPdf', pdfFile);
        }
        if (zipFile) {
          fileData.append('testcasesZip', zipFile);
        }

        setUploadProgress({ status: 'uploading', message: 'Uploading files to server...' });

        const data = await adminService.uploadFiles(problemIdForUpload, fileData);
        const { jobId } = data;

        if (jobId) {
          const pollInterval = setInterval(async () => {
            try {
              const progressData = await adminService.getUploadProgress(jobId);
              setUploadProgress(normalizeUploadProgress(progressData));

              if (progressData.status === 'completed' || progressData.status === 'failed') {
                clearInterval(pollInterval);
                if (progressData.status === 'completed') {
                  setIsModalOpen(false);
                  await fetchProblems();
                  setUploadProgress(null);
                }
              }
            } catch (pollError) {
              console.error('Polling error:', pollError);
              setError('Failed to get upload progress.');
              setUploadProgress({ status: 'failed', message: 'Could not retrieve processing status.' });
              clearInterval(pollInterval);
            }
          }, POLLING_INTERVALS.BATCH_PROCESS);
        } else {
          setIsModalOpen(false);
          await fetchProblems();
          setUploadProgress(null);
        }
      } else {
        setIsModalOpen(false);
        await fetchProblems();
        setUploadProgress(null);
      }
    } catch (errorValue) {
      const apiError = toApiLikeError(errorValue);
      const errorMsg = getErrorMessage(apiError, 'Failed to save problem.');
      setError(errorMsg);
      setUploadProgress({ status: 'failed', message: errorMsg });
      console.error(apiError);
    }
  }

import { useCallback, useEffect, useState } from 'react';
import contestService from '../services/contestService';
import { POLLING_INTERVALS } from '../config/constants';
import type {
  Contest,
  ContestProblem,
  ContestProblemScore,
  ContestScoreboardEntry,
} from '../types';
import { getErrorStatus } from '../utils/error';

type ScoreValue = ContestProblemScore | null;

interface UseContestScoreboardResult {
  contest: Contest | null;
  scoreboard: ContestScoreboardEntry[];
  problems: ContestProblem[];
  loading: boolean;
  error: string;
  lastUpdate: Date | null;
  formatDateTime: (dateTime: Date | string) => string;
  getProblemScore: (userScores: Record<string, unknown> | null | undefined, problemId: string) => ScoreValue;
}

const useContestScoreboard = (contestId?: string | number): UseContestScoreboardResult => {
  const [contest, setContest] = useState<Contest | null>(null);
  const [scoreboard, setScoreboard] = useState<ContestScoreboardEntry[]>([]);
  const [problems, setProblems] = useState<ContestProblem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [lastUpdate, setLastUpdate] = useState<Date | null>(null);

  const fetchContestData = useCallback(async () => {
    if (!contestId) {
      setError('Contest not found.');
      setLoading(false);
      return;
    }

    try {
      setLoading(true);

      const [contestData, scoreboardData] = await Promise.all([
        contestService.getById(contestId),
        contestService.getScoreboard(contestId),
      ]);

      setContest(contestData);
      setScoreboard(scoreboardData.scoreboard);
      setProblems(scoreboardData.problems || []);
      setLastUpdate(new Date());
    } catch (errorValue) {
      console.error('Error fetching contest data:', errorValue);
      const status = getErrorStatus(errorValue);
      if (status === 404) {
        setError('Contest not found.');
      } else if (status === 403) {
        setError('You do not have permission to view this contest scoreboard');
      } else {
        setError('Failed to load contest scoreboard.');
      }
    } finally {
      setLoading(false);
    }
  }, [contestId]);

  const fetchScoreboard = useCallback(async () => {
    if (!contestId) {
      return;
    }

    try {
      const data = await contestService.getScoreboard(contestId);

      setScoreboard(data.scoreboard);
      setLastUpdate(new Date());
    } catch (err) {
      console.error('Error refreshing scoreboard:', err);
    }
  }, [contestId]);

  useEffect(() => {
    void fetchContestData();
  }, [fetchContestData]);

  useEffect(() => {
    let interval: ReturnType<typeof setInterval> | undefined;
    if (contest?.status === 'running') {
      interval = setInterval(() => {
        void fetchScoreboard();
      }, POLLING_INTERVALS.SCOREBOARD);
    }

    return () => {
      if (interval) {
        clearInterval(interval);
      }
    };
  }, [contest?.status, fetchScoreboard]);

  const formatDateTime = (dateTime: Date | string) => {
    return new Date(dateTime).toLocaleString('en-US', {
      hour: '2-digit',
      minute: '2-digit',
      second: '2-digit',
    });
  };

  const getProblemScore = (
    userScores: Record<string, unknown> | null | undefined,
    problemId: string,
  ): ScoreValue => {
    if (!userScores || typeof userScores !== 'object') return null;

    const problemScore = userScores[problemId] as unknown;
    if (!problemScore) return null;

    if (typeof problemScore === 'number') {
      return {
        score: problemScore,
        attempts: 1,
        solved: problemScore === 100,
      };
    }

    if (typeof problemScore === 'object') {
      const normalizedScore = problemScore as Partial<ContestProblemScore>;
      return {
        score: normalizedScore.score ?? 0,
        attempts: normalizedScore.attempts ?? 1,
        solved: (normalizedScore.score ?? 0) === 100,
      };
    }

    return null;
  };

  return {
    contest,
    scoreboard,
    problems,
    loading,
    error,
    lastUpdate,
    formatDateTime,
    getProblemScore,
  };
};

export default useContestScoreboard;

