import { useParams, Link } from 'react-router-dom';
import useContestScoreboard from '../../hooks/useContestScoreboard';
import styles from './ContestScoreboard.module.css';
import tableStyles from '../../components/styles/Table.module.css';
import LoadingPage from '../../components/shared/LoadingPage';

const ContestScoreboard = () => {
  const { contestId } = useParams();

  const {
    contest,
    scoreboard,
    problems,
    loading,
    error,
    lastUpdate,
    formatDateTime,
    getProblemScore
  } = useContestScoreboard(contestId);

  if (loading) return <LoadingPage />;

  if (error) {
    return (
      <div className={styles.container}>
        <div className={styles.error}>
          <h3>Error: {error}</h3>
          <Link to="/contests" className={styles.backLink}>
            ← Back to Contests
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <h1>Contest Scoreboard</h1>
      {lastUpdate && contest?.status !== 'finished' && (
        <div className={styles.refreshInfo}>
          <p>Last updated: {formatDateTime(lastUpdate)}</p>
        </div>
      )}

      {scoreboard.length === 0 ? (
        <div className={styles.noData}>
          <h3>No ranking data yet</h3>
          <p>No participants have submitted solutions in this contest yet</p>
        </div>
      ) : (
        <div className={tableStyles['table-container']}>
          <table className={`${tableStyles.table} ${styles.scoreboardTable}`}>
            <thead>
              <tr>
                <th>Rank</th>
                <th>Participant</th>
                <th>Total Score</th>
                {problems.map((problem) => (
                  <th key={problem.problem_id ?? problem.id}>
                    <div className={styles.problemHeader}>
                      <div className={styles.problemId}>{problem.problem_id ?? problem.id}</div>
                    </div>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {scoreboard.map((participant, index) => {
                const rank = index + 1;
                return (
                  <tr
                    key={participant.user_id ?? `${participant.username}-${index}`}
                    className={rank <= 3 ? `rank-${rank}` : ''}
                  >
                    <td>{rank}</td>
                    <td>{participant.username}</td>
                    <td>{participant.total_score}</td>
                    {problems.map((problem) => {
                      const problemId = problem.problem_id ?? problem.id;
                      const problemScore = getProblemScore(
                        participant.detailed_scores,
                        problemId
                      );

                      return (
                        <td key={problemId}>
                          {problemScore ? (
                            <div
                              className={`${styles.problemScore} ${problemScore.solved
                                ? styles.solved
                                : problemScore.score > 0
                                  ? styles.partial
                                  : ''
                                }`}
                            >
                              <span className={styles.score}>{problemScore.score}</span>
                            </div>
                          ) : (
                            <div className={styles.noAttempt}>-</div>
                          )}
                        </td>
                      );
                    })}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default ContestScoreboard;

ContestScoreboard = () => {
  const { contestId } = useParams();

  const {
    contest,
    scoreboard,
    problems,
    loading,
    error,
    lastUpdate,
    formatDateTime,
    getProblemScore
  } = useContestScoreboard(contestId);

  if (loading) return <LoadingPage />;

  if (error) {
    return (
      <div className={styles.container}>
        <div className={styles.error}>
          <h3>Error: {error}</h3>
          <Link to="/contests" className={styles.backLink}>
            ← Back to Contests
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <h1>Contest Scoreboard</h1>
      {lastUpdate && contest?.status !== 'finished' && (
        <div className={styles.refreshInfo}>
          <p>Last updated: {formatDateTime(lastUpdate)}</p>
        </div>
      )}

      {scoreboard.length === 0 ? (
        <div className={styles.noData}>
          <h3>No ranking data yet</h3>
          <p>No participants have submitted solutions in this contest yet</p>
        </div>
      ) : (
        <div className={tableStyles['table-container']}>
          <table className={`${tableStyles.table} ${styles.scoreboardTable}`}>
            <thead>
              <tr>
                <th>Rank</th>
                <th>Participant</th>
                <th>Total Score</th>
                {problems.map((problem) => (
                  <th key={problem.problem_id ?? problem.id}>
                    <div className={styles.problemHeader}>
                      <div className={styles.problemId}>{problem.problem_id ?? problem.id}</div>
                    </div>
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {scoreboard.map((participant, index) => {
                const rank = index + 1;
                return (
                  <tr
                    key={participant.user_id ?? `${participant.username}-${index}`}
                    className={rank <= 3 ? `rank-${rank}` : ''}
                  >
                    <td>{rank}</td>
                    <td>{participant.username}</td>
                    <td>{participant.total_score}</td>
                    {problems.map((problem) => {
                      const problemId = problem.problem_id ?? problem.id;
                      const problemScore = getProblemScore(
                        participant.detailed_scores,
                        problemId
                      );

                      return (
                        <td key={problemId}>
                          {problemScore ? (
                            <div
                              className={`${styles.problemScore} ${problemScore.solved
                                ? styles.solved
                                : problemScore.score > 0
                                  ? styles.partial
                                  : ''
                                }`}
                            >
                              <span className={styles.score}>{problemScore.score}</span>
                            </div>
                          ) : (
                            <div className={styles.noAttempt}>-</div>
                          )}
                        </td>
                      );
                    })}
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { Link, useParams } from 'react-router-dom';
import styles from '../../components/styles/Submissions.module.css';
import SubmissionModal from '../../features/problem/submission/SubmissionModal';
import { useSubmissions } from '../../hooks/useSubmissions';
import { getStatusClass } from '../../utils/formatters';
import tableStyles from '../../components/styles/Table.module.css';
import LoadingPage from '../../components/shared/LoadingPage';
import { USER_ROLES } from '../../utils/constants';

type SubmissionsProps = {
  problemId?: string | null;
  contestId?: string | null;
  showTitle?: boolean;
};

const Submissions = ({ problemId = null, contestId = null, showTitle = true }: SubmissionsProps) => {
  const { contestId: contestIdFromParams } = useParams();
  const effectiveContestId = contestId ?? contestIdFromParams ?? null;

  // Logic is now completely in the Hook
  const {
    submissions,
    currentUser,
    loading,
    error,
    filter,
    setFilter,
    selectedSubmission,
    isModalOpen,
    filterProblemId,
    filterUserId,
    problemSuggestions,
    userSuggestions,
    showProblemSuggestions,
    setShowProblemSuggestions,
    showUserSuggestions,
    setShowUserSuggestions,
    handleApplyFilters,
    handleViewCode,
    handleCloseModal,
    handleProblemChange,
    handleUserChange,
    selectProblem,
    selectUser
  } = useSubmissions(problemId, effectiveContestId);

  // UI Only state
  const [visibleCount, setVisibleCount] = useState(10);
  const problemInputRef = useRef(null);
  const userInputRef = useRef(null);

  // Click outside detection for suggestions
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (problemInputRef.current && !problemInputRef.current.contains(event.target)) {
        setShowProblemSuggestions(false);
      }
      if (userInputRef.current && !userInputRef.current.contains(event.target)) {
        setShowUserSuggestions(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [setShowProblemSuggestions, setShowUserSuggestions]);



  if (loading) return <LoadingPage />;
  if (error) return <div className="error-message">{error}</div>;

  return (
    <div className={styles['submissions-container']}>
      {showTitle && (
        <div className={styles['submissions-header']}>
          <h1>Recent Submissions</h1>
          {!problemId && (
            <div className={styles['filter-buttons']}>
              <button
                className={`${styles['filter-btn']} ${filter === 'all' ? styles.active : ''}`}
                onClick={() => setFilter('all')}
              >
                All Submissions
              </button>
              <button
                className={`${styles['filter-btn']} ${filter === 'mine' ? styles.active : ''}`}
                onClick={() => setFilter('mine')}
              >
                My Submissions
              </button>

              {/* Admin/Staff Filters */}
              {currentUser && (currentUser.role === USER_ROLES.ADMIN || currentUser.role === USER_ROLES.STAFF) && (
                <>
                  <div className={styles['filter-input-wrapper']} ref={problemInputRef}>
                    <input
                      type="text"
                      placeholder="Filter by Problem ID"
                      value={filterProblemId}
                      onChange={handleProblemChange}
                      onFocus={() => filterProblemId && setShowProblemSuggestions(true)}
                      className={styles['filter-input']}
                    />
                    {showProblemSuggestions && problemSuggestions.length > 0 && (
                      <ul className={styles['suggestions-list']}>
                        {problemSuggestions.map(p => (
                          <li key={p.id} onClick={() => selectProblem(p.id)}>
                            {p.id} - {p.title}
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>

                  <div className={styles['filter-input-wrapper']} ref={userInputRef}>
                    <input
                      type="text"
                      placeholder="Filter by Username"
                      value={filterUserId}
                      onChange={handleUserChange}
                      onFocus={() => filterUserId && setShowUserSuggestions(true)}
                      className={styles['filter-input']}
                    />
                    {showUserSuggestions && userSuggestions.length > 0 && (
                      <ul className={styles['suggestions-list']}>
                        {userSuggestions.map(u => (
                          <li key={u.username} onClick={() => selectUser(u.username)}>
                            {u.username}
                          </li>
                        ))}
                      </ul>
                    )}
                  </div>

                  <button className={styles['filter-btn']} onClick={handleApplyFilters}>
                    Apply Filters
                  </button>
                </>
              )}
            </div>
          )}
        </div>
      )}

      <div className={tableStyles['table-container']}>
        {submissions.length === 0 ? (
          <div className={styles['no-submissions']}>
            <p>
              {problemId ? "You haven't made any submissions for this problem yet." : "No submissions found."}
            </p>
          </div>
        ) : (
          <table className={tableStyles.table}>
            <thead>
              <tr>
                <th>When</th>
                <th>User</th>
                {!problemId && <th>Problem</th>}
                <th>Status</th>
                <th>Score</th>
                <th>Language</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {submissions.slice(0, visibleCount).map(sub => (
                <tr key={sub.id}>
                  <td>{new Date(sub.submitted_at).toLocaleString()}</td>
                  <td>{sub.username}</td>
                  {!problemId && (
                    <td><Link to={`/problems/${sub.problem_id}`}>{sub.problem_title}</Link></td>
                  )}
                  <td className={getStatusClass(sub.overall_status)}>{sub.overall_status}</td>
                  <td>{sub.score}</td>
                  <td>{sub.language}</td>
                  <td>
                    {currentUser && (currentUser.username === sub.username || currentUser.role === USER_ROLES.ADMIN || currentUser.role === USER_ROLES.STAFF) && (
                      <button onClick={() => handleViewCode(sub.id)} className={styles['view-code-btn']}>
                        View Code
                      </button>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {visibleCount < submissions.length && (
        <div className={styles['show-more-container']}>
          <button
            className={styles['show-more-btn']}
            onClick={() => setVisibleCount(prev => prev + 10)}
          >
            Show More
          </button>
        </div>
      )}

      {isModalOpen && (
        <SubmissionModal submission={selectedSubmission} onClose={handleCloseModal} />
      )}
    </div>
  );
}

