import { Request, Response, NextFunction } from 'express';
import { requireAuth, requireStaffOrAdmin, requireAdmin } from '../../middleware/auth';

describe('Auth Middleware', () => {
    let req: Partial<Request>;
    let res: Partial<Response>;
    let next: NextFunction;

    beforeEach(() => {
        req = { session: {} as any };
        res = {
            status: jest.fn().mockReturnThis(),
            json: jest.fn(),
        };
        next = jest.fn();
    });

    describe('requireAuth', () => {
        it('calls next when userId exists in session', () => {
            if (req.session) req.session.userId = 1;

            requireAuth(req as Request, res as Response, next);

            expect(next).toHaveBeenCalled();
            expect(res.status).not.toHaveBeenCalled();
        });

        it('returns 401 when userId is not in session', () => {
            requireAuth(req as Request, res as Response, next);

            expect(res.status).toHaveBeenCalledWith(401);
            expect(res.json).toHaveBeenCalledWith({ message: 'Authentication required' });
            expect(next).not.toHaveBeenCalled();
        });
    });

    describe('requireStaffOrAdmin', () => {
        it('calls next when role is admin', () => {
            if (req.session) req.session.role = 'admin';

            requireStaffOrAdmin(req as Request, res as Response, next);

            expect(next).toHaveBeenCalled();
            expect(res.status).not.toHaveBeenCalled();
        });

        it('calls next when role is staff', () => {
            if (req.session) req.session.role = 'staff';

            requireStaffOrAdmin(req as Request, res as Response, next);

            expect(next).toHaveBeenCalled();
            expect(res.status).not.toHaveBeenCalled();
        });

        it('returns 403 when role is not admin or staff', () => {
            if (req.session) req.session.role = 'user';

            requireStaffOrAdmin(req as Request, res as Response, next);

            expect(res.status).toHaveBeenCalledWith(403);
            expect(res.json).toHaveBeenCalledWith({ message: 'Staff or Admin access required' });
            expect(next).not.toHaveBeenCalled();
        });

        it('returns 403 when role is undefined', () => {
            requireStaffOrAdmin(req as Request, res as Response, next);

            expect(res.status).toHaveBeenCalledWith(403);
            expect(next).not.toHaveBeenCalled();
        });
    });

    describe('requireAdmin', () => {
        it('calls next when role is admin', () => {
            if (req.session) req.session.role = 'admin';

            requireAdmin(req as Request, res as Response, next);

            expect(next).toHaveBeenCalled();
            expect(res.status).not.toHaveBeenCalled();
        });

        it('returns 403 when role is staff', () => {
            if (req.session) req.session.role = 'staff';

            requireAdmin(req as Request, res as Response, next);

            expect(res.status).toHaveBeenCalledWith(403);
            expect(res.json).toHaveBeenCalledWith({ message: 'Admin access required' });
            expect(next).not.toHaveBeenCalled();
        });

        it('returns 403 when role is user', () => {
            if (req.session) req.session.role = 'user';

            requireAdmin(req as Request, res as Response, next);

            expect(res.status).toHaveBeenCalledWith(403);
            expect(next).not.toHaveBeenCalled();
        });
    });
});

import path from 'path';
import fs from 'fs';
import { memoryUpload, diskUpload } from '../../middleware/upload';
import { Request } from 'express';

// Mock fs to avoid actually creating directories during tests
jest.mock('fs', () => ({
    existsSync: jest.fn(),
    mkdirSync: jest.fn(),
}));

describe('Upload Middleware', () => {
    beforeEach(() => {
        jest.clearAllMocks();
    });

    describe('memoryUpload', () => {
        it('should use memory storage', () => {
            // Memory storage is mostly opaque, but we can verify it was created
            expect((memoryUpload as any).storage).toBeDefined();
            expect((memoryUpload as any).storage.constructor.name).toBe('MemoryStorage');
        });
    });

    describe('diskUpload', () => {
        it('should define a disk storage with destination and filename functions', () => {
            expect((diskUpload as any).storage).toBeDefined();
            const storage = (diskUpload as any).storage;
            expect(storage.getDestination).toBeInstanceOf(Function);
            expect(storage.getFilename).toBeInstanceOf(Function);
        });

        it('should set destination to /tmp/oj_uploads and create directory if it does not exist', () => {
            (fs.existsSync as jest.Mock).mockReturnValue(false); // Simulate dir not existing

            const req = {} as Request;
            const file = {} as any;
            const cb = jest.fn();

            // Invoke the destination function
            const storage = (diskUpload as any).storage;
            storage.getDestination(req, file, cb);

            // Verify fs functions were called
            const expectedPath = path.join('/tmp', 'oj_uploads');
            expect(fs.existsSync).toHaveBeenCalledWith(expectedPath);
            expect(fs.mkdirSync).toHaveBeenCalledWith(expectedPath, { recursive: true });

            // Verify callback was called with correct path
            expect(cb).toHaveBeenCalledWith(null, expectedPath);
        });

        it('should set destination without creating directory if it already exists', () => {
            (fs.existsSync as jest.Mock).mockReturnValue(true); // Simulate dir existing

            const req = {} as Request;
            const file = {} as any;
            const cb = jest.fn();

            const storage = (diskUpload as any).storage;
            storage.getDestination(req, file, cb);

            const expectedPath = path.join('/tmp', 'oj_uploads');
            expect(fs.existsSync).toHaveBeenCalledWith(expectedPath);
            expect(fs.mkdirSync).not.toHaveBeenCalled();
            expect(cb).toHaveBeenCalledWith(null, expectedPath);
        });

        it('should generate a unique filename retaining original extension', () => {
            const req = {} as Request;
            const file = { fieldname: 'testFile', originalname: 'document.pdf' } as any;
            const cb = jest.fn();

            // Mock Date.now and Math.random to verify exact string pattern
            const mockDateNow = 1678886400000;
            const mockRandom = 0.5;
            jest.spyOn(Date, 'now').mockReturnValue(mockDateNow);
            jest.spyOn(Math, 'random').mockReturnValue(mockRandom);

            const storage = (diskUpload as any).storage;
            storage.getFilename(req, file, cb);

            const expectedSuffix = `${mockDateNow}-${Math.round(mockRandom * 1E9)}`;
            const expectedExt = '.pdf';
            const expectedFilename = `testFile-${expectedSuffix}${expectedExt}`;

            expect(cb).toHaveBeenCalledWith(null, expectedFilename);

            // Restore mocks
            (Date.now as jest.Mock).mockRestore();
            (Math.random as jest.Mock).mockRestore();
        });
    });
});

import request from 'supertest';
import express, { Express, Request, Response, NextFunction } from 'express';
import session from 'express-session';
import authRouter from '../controllers/authController';
import * as db from '../db';
import bcrypt from 'bcrypt';

// Mock the database
jest.mock('../db');

describe('Auth Controller', () => {
    let app: Express;

    beforeEach(() => {
        app = express();
        app.use(express.json());
        app.use(session({
            secret: 'test-secret',
            resave: false,
            saveUninitialized: false,
        }));
        app.use('/', authRouter);
        jest.resetAllMocks();
    });

    describe('POST /register', () => {
        it('should return 400 for invalid payload', async () => {
            const res = await request(app)
                .post('/register')
                .send({ username: '', password: '123' });

            expect(res.status).toBe(400);
            expect(res.body.message).toBe('Validation failed');
            expect(Array.isArray(res.body.errors)).toBe(true);
        });

        it('should return 403 if registration is disabled', async () => {
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ setting_value: 'false' }] });

            const res = await request(app)
                .post('/register')
                .send({ username: 'testuser', password: 'password123' });

            expect(res.status).toBe(403);
            expect(res.body.message).toBe('Registration is currently disabled.');
        });

        it('should register a user successfully when enabled', async () => {
            // 1. Check registration enabled
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ setting_value: 'true' }] });
            // 2. Check if username exists (no)
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [] });
            // 3. Insert user
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ id: 1, username: 'testuser' }] });

            const res = await request(app)
                .post('/register')
                .send({ username: 'testuser', password: 'password123' });

            expect(res.status).toBe(201);
            expect(res.body.message).toBe('User registered successfully');
            expect(res.body.user.username).toBe('testuser');
        });

        it('should return 400 if username already exists', async () => {
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ setting_value: 'true' }] });
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ id: 1, username: 'testuser' }] });

            const res = await request(app)
                .post('/register')
                .send({ username: 'testuser', password: 'password123' });

            expect(res.status).toBe(400);
            expect(res.body.message).toBe('Username already exists');
        });
    });

    describe('GET /settings/registration', () => {
        it('should return enabled=true when setting row is missing', async () => {
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [] });

            const res = await request(app).get('/settings/registration');

            expect(res.status).toBe(200);
            expect(res.body).toEqual({ enabled: true });
        });

        it('should return enabled=false when setting is false', async () => {
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ setting_value: 'false' }] });

            const res = await request(app).get('/settings/registration');

            expect(res.status).toBe(200);
            expect(res.body).toEqual({ enabled: false });
        });
    });

    describe('POST /login', () => {
        it('should return 400 for invalid login payload', async () => {
            const res = await request(app)
                .post('/login')
                .send({ username: '' });

            expect(res.status).toBe(400);
            expect(res.body.message).toBe('Validation failed');
        });

        it('should login successfully with correct credentials', async () => {
            const hashedPassword = await bcrypt.hash('password123', 10);
            (db.query as jest.Mock).mockResolvedValueOnce({
                rows: [{ id: 1, username: 'testuser', password_hash: hashedPassword, role: 'user' }]
            });

            const res = await request(app)
                .post('/login')
                .send({ username: 'testuser', password: 'password123' });

            expect(res.status).toBe(200);
            expect(res.body.message).toBe('Login successful');
            expect(res.body.user.username).toBe('testuser');
        });

        it('should return 401 for wrong password', async () => {
            const hashedPassword = await bcrypt.hash('password123', 10);
            (db.query as jest.Mock).mockResolvedValueOnce({
                rows: [{ id: 1, username: 'testuser', password_hash: hashedPassword, role: 'user' }]
            });

            const res = await request(app)
                .post('/login')
                .send({ username: 'testuser', password: 'wrongpassword' });

            expect(res.status).toBe(401);
            expect(res.body.message).toBe('Wrong Password');
        });

        it('should return 401 if user not found', async () => {
            (db.query as jest.Mock).mockResolvedValueOnce({ rows: [] });

            const res = await request(app)
                .post('/login')
                .send({ username: 'nonexistent', password: 'password123' });

            expect(res.status).toBe(401);
            expect(res.body.message).toBe('User not found');
        });
    });

    describe('POST /logout', () => {
        it('should logout successfully', async () => {
            const res = await request(app).post('/logout');

            expect(res.status).toBe(200);
            expect(res.body.message).toBe('Logout successful');
        });
    });

    describe('GET /me', () => {
        it('should return user info if authenticated', async () => {
            const res = await request(app).get('/me');
            expect(res.body.isAuthenticated).toBe(false);
        });

        it('should return authenticated user when req.user is present', async () => {
            const appWithUser = express();
            appWithUser.use(express.json());
            appWithUser.use(session({
                secret: 'test-secret',
                resave: false,
                saveUninitialized: false,
            }));
            appWithUser.use((req: Request, _res: Response, next: NextFunction) => {
                req.user = { id: 1, username: 'tester', role: 'user' };
                next();
            });
            appWithUser.use('/', authRouter);

            const res = await request(appWithUser).get('/me');
            expect(res.status).toBe(200);
            expect(res.body.isAuthenticated).toBe(true);
            expect(res.body.user.username).toBe('tester');
        });
    });
});

