import { judge } from '../../services/judgeService';
import * as db from '../../db';
import cp from 'child_process';
import { SUBMISSION_STATUS } from '../../constants';

jest.mock('../../db');
jest.mock('child_process');

describe('Judge Service', () => {
    beforeEach(() => {
        jest.clearAllMocks();
    });

    it('should return system error if problem not found', async () => {
        (db.query as jest.Mock).mockResolvedValueOnce({ rows: [] });

        const result = await judge('P1', '/tmp/a.out');
        expect(result.overallStatus).toBe(SUBMISSION_STATUS.SYSTEM_ERROR);
    });

    it('should return system error if no testcases exist', async () => {
        (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ time_limit_ms: 1000, memory_limit_mb: 256 }] }); // Problem
        (db.query as jest.Mock).mockResolvedValueOnce({ rows: [] }); // Testcases

        const result = await judge('P1', '/tmp/a.out');
        expect(result.overallStatus).toBe(SUBMISSION_STATUS.SYSTEM_ERROR);
    });

    it('should judge an Accepted submission correctly', async () => {
        (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ time_limit_ms: 1000, memory_limit_mb: 256 }] });
        (db.query as jest.Mock).mockResolvedValueOnce({
            rows: [
                { case_number: 1, input_data: '1 2', output_data: '3' },
                { case_number: 2, input_data: '2 3', output_data: '5' }
            ]
        });

        // Mock child process exec to succeed for both test cases
        const mockChild1 = { stdin: { write: jest.fn(), end: jest.fn(), on: jest.fn() }, on: jest.fn() };
        const mockChild2 = { stdin: { write: jest.fn(), end: jest.fn(), on: jest.fn() }, on: jest.fn() };

        (cp.exec as unknown as jest.Mock)
            .mockImplementationOnce((cmd, opts, cb) => {
                cb(null, '3\n', ''); // stdout, stderr
                return mockChild1;
            })
            .mockImplementationOnce((cmd, opts, cb) => {
                cb(null, '5\n', ''); // stdout, stderr
                return mockChild2;
            });

        const result = await judge('P1', '/tmp/a.out');

        expect(result.score).toBe(100);
        expect(result.overallStatus).toBe(SUBMISSION_STATUS.ACCEPTED);
        expect(result.results).toHaveLength(2);
        expect(result.results[0].status).toBe(SUBMISSION_STATUS.ACCEPTED);
        expect(result.results[1].status).toBe(SUBMISSION_STATUS.ACCEPTED);
    });

    it('should correctly handle Wrong Answer', async () => {
        (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ time_limit_ms: 1000, memory_limit_mb: 256 }] });
        (db.query as jest.Mock).mockResolvedValueOnce({
            rows: [
                { case_number: 1, input_data: '1 2', output_data: '3' },
                { case_number: 2, input_data: '2 3', output_data: '5' } // This won't be run if case 1 fails immediately
            ]
        });

        const mockChild = { stdin: { write: jest.fn(), end: jest.fn(), on: jest.fn() }, on: jest.fn() };

        (cp.exec as unknown as jest.Mock).mockImplementationOnce((cmd, opts, cb) => {
            cb(null, 'wrong\n', ''); // Output doesn't match
            return mockChild;
        });

        const result = await judge('P1', '/tmp/a.out');

        expect(result.score).toBe(0); // Failed first case
        expect(result.overallStatus).toBe(SUBMISSION_STATUS.WRONG_ANSWER);
        // Since it breaks early, the second case is skipped
        expect(result.results[0].status).toBe(SUBMISSION_STATUS.WRONG_ANSWER);
        expect(result.results[1].status).toBe(SUBMISSION_STATUS.SKIPPED);
    });

    it('should correctly parse TLE', async () => {
        (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ time_limit_ms: 1000, memory_limit_mb: 256 }] });
        (db.query as jest.Mock).mockResolvedValueOnce({ rows: [{ case_number: 1, input_data: '', output_data: '' }] });

        const mockChild = { stdin: { write: jest.fn(), end: jest.fn(), on: jest.fn() }, on: jest.fn() };

        (cp.exec as unknown as jest.Mock).mockImplementationOnce((cmd, opts, cb) => {
            const tleError = new Error('Command failed') as any;
            tleError.code = 124; // Timeout exit code
            cb(tleError, '', '');
            return mockChild;
        });

        const result = await judge('P1', '/tmp/a.out');
        expect(result.overallStatus).toBe(SUBMISSION_STATUS.TIME_LIMIT_EXCEEDED);
    });
});

import contestScheduler from '../../services/contestScheduler';
import * as db from '../../db';
import { migrateSubmissionsAfterContest } from '../../services/problemMigration';
import cron from 'node-cron';

jest.mock('../../db');
jest.mock('../../services/problemMigration');
jest.mock('node-cron', () => ({
    schedule: jest.fn(() => ({ stop: jest.fn() }))
}));

describe('Contest Scheduler Service', () => {
    beforeEach(() => {
        jest.clearAllMocks();
        console.log = jest.fn();
        console.error = jest.fn();
        (contestScheduler as any).isRunning = false;
        (contestScheduler as any).checkInterval = null;
    });

    describe('start / stop', () => {
        it('should start the scheduler and register a cron job', () => {
            contestScheduler.start();
            expect(contestScheduler.getStatus().isRunning).toBe(true);
            expect(cron.schedule).toHaveBeenCalledWith('* * * * *', expect.any(Function), expect.any(Object));
        });

        it('should not start multiple instances', () => {
            contestScheduler.start();
            contestScheduler.start();
            expect(cron.schedule).toHaveBeenCalledTimes(1);
        });

        it('should stop the scheduler', () => {
            contestScheduler.start();
            const mockStop = (contestScheduler as any).checkInterval.stop;

            contestScheduler.stop();

            expect(contestScheduler.getStatus().isRunning).toBe(false);
            expect(mockStop).toHaveBeenCalled();
        });
    });

    describe('checkContestStatus', () => {
        it('should start scheduled contests that have reached start_time', async () => {
            const mockNow = new Date('2025-01-01T12:00:00Z');
            jest.useFakeTimers().setSystemTime(mockNow);

            (db.query as jest.Mock)
                .mockResolvedValueOnce({ rows: [{ id: 1, title: 'Contest 1' }] }) // start scheduled
                .mockResolvedValueOnce({}) // UPDATE to running
                .mockResolvedValueOnce({ rows: [] }); // end running (none)

            await contestScheduler.checkContestStatus();

            expect(db.query).toHaveBeenNthCalledWith(1, expect.stringContaining('SELECT id, title, start_time'), [mockNow]);
            expect(db.query).toHaveBeenNthCalledWith(2, expect.stringContaining('UPDATE contests \n          SET status = \'running\''), [1]);

            jest.useRealTimers();
        });

        it('should end running contests, trigger migration, and mark finishing', async () => {
            const mockNow = new Date('2025-01-01T15:00:00Z');
            jest.useFakeTimers().setSystemTime(mockNow);

            (db.query as jest.Mock)
                .mockResolvedValueOnce({ rows: [] }) // start scheduled (none)
                .mockResolvedValueOnce({ rows: [{ id: 2, title: 'Contest 2' }] }) // end running
                .mockResolvedValueOnce({}); // UPDATE to finishing

            (migrateSubmissionsAfterContest as jest.Mock).mockResolvedValueOnce({});

            await contestScheduler.checkContestStatus();

            expect(db.query).toHaveBeenNthCalledWith(3, expect.stringContaining('UPDATE contests \n          SET status = \'finishing\''), [2]);
            expect(migrateSubmissionsAfterContest).toHaveBeenCalledWith(2);

            jest.useRealTimers();
        });

        it('should still mark contest as finished if migration fails', async () => {
            const mockNow = new Date('2025-01-01T15:00:00Z');
            jest.useFakeTimers().setSystemTime(mockNow);

            (db.query as jest.Mock)
                .mockResolvedValueOnce({ rows: [] })
                .mockResolvedValueOnce({ rows: [{ id: 3, title: 'Contest 3' }] })
                .mockResolvedValueOnce({}) // finishing
                .mockResolvedValueOnce({}); // fallback to finished

            const error = new Error('Migration failed');
            (migrateSubmissionsAfterContest as jest.Mock).mockRejectedValueOnce(error);

            await contestScheduler.checkContestStatus();

            expect(console.error).toHaveBeenCalledWith(expect.stringContaining('Error migrating'), error);
            expect(db.query).toHaveBeenNthCalledWith(4, expect.stringContaining('UPDATE contests \n            SET status = \'finished\''), [3]);

            jest.useRealTimers();
        });
    });
});

export const getErrorMessage = (error: unknown, fallback = 'Unknown error'): string => {
  if (error instanceof Error && typeof error.message === 'string' && error.message.length > 0) {
    return error.message;
  }
  return fallback;
};

getErrorMessage = (error: unknown, fallback = 'Unknown error'): string => {
  if (error instanceof Error && typeof error.message === 'string' && error.message.length > 0) {
    return error.message;
  }
  return fallback;
}

